"use client"

import * as React from "react"
import { Combobox } from "@base-ui/react/combobox"
import { cn } from "@/lib/utils"

export interface AutocompleteOption {
  value: string
  label: string
  disabled?: boolean
}

export interface AutocompleteProps {
  options: AutocompleteOption[]
  value?: string
  onValueChange?: (value: string) => void
  placeholder?: string
  emptyText?: string
  label?: string
  error?: string
  disabled?: boolean
  className?: string
  filterFn?: (option: AutocompleteOption, inputValue: string) => boolean
}

export function Autocomplete({
  options,
  value,
  onValueChange,
  placeholder = "Search...",
  emptyText = "No results found.",
  label,
  error,
  disabled,
  className,
  filterFn,
}: AutocompleteProps) {
  const inputId = React.useId()
  const [inputValue, setInputValue] = React.useState(value ?? "")

  const filtered = React.useMemo(() => {
    if (!inputValue) return options
    const fn = filterFn ?? ((opt, v) => opt.label.toLowerCase().includes(v.toLowerCase()))
    return options.filter((opt) => fn(opt, inputValue))
  }, [options, inputValue, filterFn])

  return (
    <div className="flex flex-col gap-1.5">
      {label && (
        <label htmlFor={inputId} className="text-sm font-medium text-foreground">
          {label}
        </label>
      )}
      <Combobox.Root
        value={value}
        onValueChange={(val) => {
          onValueChange?.(val as string)
          setInputValue(val as string)
        }}
        disabled={disabled}
      >
        <Combobox.Input
          id={inputId}
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          placeholder={placeholder}
          className={cn(
            "flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm",
            "placeholder:text-muted-foreground",
            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
            "disabled:cursor-not-allowed disabled:opacity-50",
            error && "border-destructive focus-visible:ring-destructive",
            className
          )}
          aria-invalid={!!error}
        />
        <Combobox.Popup className="z-50">
          <Combobox.Positioner sideOffset={6}>
            <Combobox.Listbox
              className={cn(
                "w-[var(--anchor-width)] min-w-[8rem] overflow-hidden rounded-md border border-border bg-popover text-popover-foreground shadow-md",
                "max-h-56 overflow-y-auto p-1"
              )}
            >
              {filtered.length === 0 ? (
                <div className="py-6 text-center text-sm text-muted-foreground">{emptyText}</div>
              ) : (
                filtered.map((opt) => (
                  <Combobox.Item
                    key={opt.value}
                    value={opt.value}
                    label={opt.label}
                    disabled={opt.disabled}
                    className={cn(
                      "relative flex w-full cursor-default select-none items-center rounded-sm px-2 py-1.5 text-sm outline-none",
                      "data-[highlighted]:bg-accent data-[highlighted]:text-accent-foreground",
                      "data-[disabled]:pointer-events-none data-[disabled]:opacity-50"
                    )}
                  >
                    <Combobox.ItemText>{opt.label}</Combobox.ItemText>
                  </Combobox.Item>
                ))
              )}
            </Combobox.Listbox>
          </Combobox.Positioner>
        </Combobox.Popup>
      </Combobox.Root>
      {error && <p className="text-xs text-destructive">{error}</p>}
    </div>
  )
}
